import type { NextApiRequest, NextApiResponse } from "next";
import { query } from "../../lib/db";
import { listaData } from "../../data/community";

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Método não permitido" });
  }

  try {
    for (const community of listaData) {
      // 1️⃣ Inserir comunidade
      const { rows } = await query(
        `INSERT INTO communities (logo, title, description, website, mail, color)
         VALUES ($1,$2,$3,$4,$5,$6) RETURNING id`,
        [
          community.logo,
          community.title,
          community.description,
          community.website || null,
          community.mail || null,
          community.color,
        ]
      );
      const communityId = rows[0].id;

      // 2️⃣ Inserir categorias
      for (const cat of community.categories) {
        await query(
          `INSERT INTO community_categories (community_id, category) VALUES ($1, $2)`,
          [communityId, cat]
        );
      }
    }

    return res.status(200).json({ message: "Comunidades inseridas com sucesso" });
  } catch (err) {
    console.error(err);
    return res.status(500).json({ error: "Erro ao inserir comunidades" });
  }
}
